-- ============================================================
-- Publications table — CMS for blog posts
-- ============================================================

CREATE TABLE public.publications (
  id           uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  slug         text NOT NULL UNIQUE,
  title        text NOT NULL,
  tag          text NOT NULL DEFAULT 'Мнение',
  excerpt      text NOT NULL DEFAULT '',
  body         text NOT NULL DEFAULT '',
  published_at date NOT NULL DEFAULT CURRENT_DATE,
  telegram_url text,
  is_visible   boolean NOT NULL DEFAULT true,
  display_order integer NOT NULL DEFAULT 0,
  created_at   timestamptz NOT NULL DEFAULT now(),
  updated_at   timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX publications_published_at_idx
  ON public.publications (published_at DESC);

CREATE INDEX publications_visible_idx
  ON public.publications (is_visible);

-- RLS
ALTER TABLE public.publications ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Publications are publicly readable"
  ON public.publications
  FOR SELECT
  USING (true);

CREATE POLICY "Admins can insert publications"
  ON public.publications
  FOR INSERT
  TO authenticated
  WITH CHECK (public.has_role(auth.uid(), 'admin'::public.app_role));

CREATE POLICY "Admins can update publications"
  ON public.publications
  FOR UPDATE
  TO authenticated
  USING (public.has_role(auth.uid(), 'admin'::public.app_role))
  WITH CHECK (public.has_role(auth.uid(), 'admin'::public.app_role));

CREATE POLICY "Admins can delete publications"
  ON public.publications
  FOR DELETE
  TO authenticated
  USING (public.has_role(auth.uid(), 'admin'::public.app_role));

-- updated_at trigger
CREATE TRIGGER publications_set_updated_at
  BEFORE UPDATE ON public.publications
  FOR EACH ROW
  EXECUTE FUNCTION public.set_updated_at();

-- realtime
ALTER TABLE public.publications REPLICA IDENTITY FULL;
ALTER PUBLICATION supabase_realtime ADD TABLE public.publications;

